## 2. Production Telemetry (Lock-Free Metrics)

Ops needs dashboards. Since we can't pull in `prometheus`, we build a zero-allocation atomic registry.

```rust
use std::sync::atomic::{AtomicU64, Ordering};

pub struct Metrics {
    pub queries_total: AtomicU64,
    pub queries_rejected_idf: AtomicU64,
    pub sweep_tasks_completed: AtomicU64,
    pub delta_merges: AtomicU64,
    pub admission_rejects: AtomicU64,
    pub staleness_peak_ms: AtomicU64,
}

impl Metrics {
    pub fn new() -> Self {
        Self {
            queries_total: AtomicU64::new(0),
            queries_rejected_idf: AtomicU64::new(0),
            sweep_tasks_completed: AtomicU64::new(0),
            delta_merges: AtomicU64::new(0),
            admission_rejects: AtomicU64::new(0),
            staleness_peak_ms: AtomicU64::new(0),
        }
    }

    /// Called by the scraping endpoint. Returns a snapshot without locking.
    pub fn snapshot(&self) -> MetricsSnapshot {
        MetricsSnapshot {
            queries_total: self.queries_total.load(Ordering::Relaxed),
            idf_clip_rate: self.queries_rejected_idf.load(Ordering::Relaxed) as f64 
                           / self.queries_total.load(Ordering::Relaxed).max(1) as f64,
            sweep_tasks_completed: self.sweep_tasks_completed.load(Ordering::Relaxed),
            delta_merges: self.delta_merges.load(Ordering::Relaxed),
            admission_rejects: self.admission_rejects.load(Ordering::Relaxed),
            staleness_peak_ms: self.staleness_peak_ms.load(Ordering::Relaxed),
        }
    }
}

pub struct MetricsSnapshot {
    pub queries_total: u64,
    pub idf_clip_rate: f64,
    pub sweep_tasks_completed: u64,
    pub delta_merges: u64,
    pub admission_rejects: u64,
